/* Local shim for html2pdf: ensures a local file exists and loads the real bundle from CDN.
   This keeps the app working offline-by-default where the CDN is reachable, and allows
   the code to prefer a local file if you replace this with the real bundle later.
*/
(function(){
  if (typeof window.html2pdf !== 'undefined') return;
  try {
    var script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
    script.crossOrigin = 'anonymous';
    script.onload = function(){
      console.log('[html2pdf-shim] html2pdf loaded from CDN');
    };
    script.onerror = function(){
      console.error('[html2pdf-shim] failed to load html2pdf from CDN');
    };
    document.head.appendChild(script);
  } catch (e) {
    console.error('[html2pdf-shim] unexpected error', e);
  }
})();
